const main = require('../../lib/jibo-emotion-system');
let Utils = main.common.Utils;

describe('Utils', () => {

    describe('.limitToRange', () => {
        it('should not exceed min value.', () => {
            let result = Utils.limitToRange(-5000, -1, 1);
            expect(result).to.equal(-1);
        });
        it('should not exceed max value.', () => {
            let result = Utils.limitToRange(5, -1, 1);
            expect(result).to.equal(1);
        });
    });
    describe('.euclidianDistance', () => {
        it('should give correct euclidian distance', () => {
            let testA = {
                'test1': 0.45,
                'test2': 0.2
            }
            let testB = {
                'test1': 1,
                'test2': 0
            }
            let result = Utils.getEuclideanDistance(testA, testB, ['test1', 'test2']);
            expect(result).to.equal(0.5852349955359812);
        });
    });

});
